const matchItem = (name, rule) => {
    if (!rule.pattern) return false;
    try {
        if (rule.matchType === "regex") {
            return new RegExp(rule.pattern).test(name);
        } else {
            return name === rule.pattern;
        }
    } catch (e) {
        shell.println(
            '[Windows 11 Icon Pack Lite] 规则 "' + rule.pattern + '" 匹配出错:',
            e.message,
        );
        return false;
    }
};

shell.menu_controller.add_menu_listener((ctx) => {
    try {
        const processMenu = (menuController) => {
            const items = menuController.get_items();
            for (const item of items) {
                const data = item.data();
                if (!data.name) {
                    if (data.submenu) {
                        const orig = data.submenu;
                        item.update_data({
                            submenu: (sub) => {
                                orig(sub);
                                processMenu(sub);
                            },
                        });
                    }
                    continue;
                }

                for (const bt of map_button) {
                    if (matchItem(data.name, bt)) {
                        const svg = icons[bt.icon];
                        if (svg) {
                            item.set_data({
                                icon_svg: svg,
                                icon_bitmap: new shell.value_reset(),
                            });
                        }
                        break;
                    }
                }

                if (data.submenu) {
                    const orig = data.submenu;
                    item.update_data({
                        submenu: (sub) => {
                            orig(sub);
                            processMenu(sub);
                        },
                    });
                }
            }
        };

        processMenu(ctx.menu);
    } catch (e) {
        shell.println(
            "[Windows 11 Icon Pack Lite] 处理出错:",
            e,
            "\n",
            e.stack,
        );
    }
});
